import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./Notes.css";

export default function Notes() {
  const navigate = useNavigate();
  const [notes, setNotes] = useState([]);
  const [newNote, setNewNote] = useState({ title: "", content: "" });

  const currentUser = JSON.parse(localStorage.getItem("currentUser"));

  useEffect(() => {
    if (!currentUser) {
      navigate("/login");
    } else {
      const storedNotes = JSON.parse(localStorage.getItem("notes")) || [];
      setNotes(storedNotes);
    }
  // ✅ Include dependencies here
  }, [currentUser, navigate]);


  const handleChange = (e) => {
    setNewNote({ ...newNote, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const noteWithMeta = {
      ...newNote,
      user: currentUser.name,
      timestamp: new Date().toLocaleString(),
    };
    const updatedNotes = [noteWithMeta, ...notes];
    localStorage.setItem("notes", JSON.stringify(updatedNotes));
    setNotes(updatedNotes);
    setNewNote({ title: "", content: "" });
  };

  const canUpload =
    currentUser?.role === "Admin" ||
    currentUser?.role === "Student" ||
    currentUser?.role === "HR";

  return (
    <div className="notes-container">
      <h1>Notes Sharing</h1>

      {canUpload && (
        <form onSubmit={handleSubmit}>
          <label>Title:</label>
          <input
            type="text"
            name="title"
            value={newNote.title}
            onChange={handleChange}
            required
          />

          <label>Content:</label>
          <textarea
            name="content"
            rows="5"
            value={newNote.content}
            onChange={handleChange}
            required
          />

          <button type="submit">Upload Note</button>
        </form>
      )}

      <h2>Uploaded Notes</h2>
      {notes.length > 0 ? (
        notes.map((note, index) => (
          <div key={index} className="note">
            <h3>{note.title}</h3>
            <p>{note.content}</p>
            <small>
              By: {note.user} | {note.timestamp}
            </small>
          </div>
        ))
      ) : (
        <p>No notes available yet.</p>
      )}

      <h2>Useful Resources</h2>
      <div className="resources">
        <div className="resource">
          <img src="https://img.icons8.com/ios-filled/100/book.png" alt="PDF" />
          <h4>DSA Notes</h4>
          <p>Comprehensive guide for Data Structures & Algorithms.</p>
          <a href="https://www.geeksforgeeks.org/data-structures/" target="_blank" rel="noopener noreferrer">View</a>
        </div>
        <div className="resource">
          <img src="https://img.icons8.com/ios-filled/100/web.png" alt="Web Dev" />
          <h4>Web Dev Cheatsheet</h4>
          <p>HTML, CSS & JavaScript snippets at a glance.</p>
          <a href="https://htmlcheatsheet.com/" target="_blank" rel="noopener noreferrer">View</a>
        </div>
        <div className="resource">
          <img src="https://img.icons8.com/ios-filled/100/python.png" alt="Python" />
          <h4>Python Notes</h4>
          <p>Learn Python syntax & logic for beginners.</p>
          <a href="https://www.programiz.com/python-programming" target="_blank" rel="noopener noreferrer">View</a>
        </div>
      </div>

      <button className="back-btn" onClick={() => navigate("/dashboard")}>
        ⬅ Back to Dashboard
      </button>
    </div>
  );
}
